// ─── Feed Content Card ────────────────────────────────────────────────────────
function FeedCard({
  item,
  onClick,
}: {
  item: ContentPublicResponse;
  onClick: () => void;
}) {
  const color = hubColor(item.hub_id);
  const cfg = TYPE_CONFIG[item.content_type] ?? TYPE_CONFIG.text;

  return (
    <article
      onClick={onClick}
      className="bg-white rounded-2xl border border-[#EDE5F8] overflow-hidden group transition-all duration-200 hover:shadow-[0_4px_24px_rgba(138,43,226,0.1)] hover:-translate-y-[1px] cursor-pointer"
    >
      <div
        className="relative h-[170px] flex items-center justify-center overflow-hidden"
        style={{
          background: `linear-gradient(135deg, ${color}18 0%, ${color}22 100%)`,
        }}
      >
        {item.thumbnail_url ? (
          <img
            src={item.thumbnail_url}
            alt={item.title}
            className="absolute inset-0 w-full h-full object-cover"
          />
        ) : item.content_type === "video" && item.file_url ? (
          <video
            src={item.file_url}
            className="absolute inset-0 w-full h-full object-cover"
            muted
            playsInline
            preload="metadata"
          />
        ) : item.content_type === "image" && item.file_url ? (
          <img
            src={item.file_url}
            alt={item.title}
            className="absolute inset-0 w-full h-full object-cover"
          />
        ) : (
          cfg.centerIcon(color)
        )}
        <span
          className="absolute top-3 left-3 flex items-center gap-1.5 text-[11px] font-semibold px-2.5 py-1 rounded-full z-10"
          style={{
            background: color,
            color: "white",
            boxShadow: `0 2px 8px ${color}55`,
          }}
        >
          {cfg.icon} {cfg.label}
        </span>
        {item.plans.length > 0 && (
          <span className="absolute top-3 right-3 text-[10px] font-bold px-2 py-0.5 rounded-full bg-white/90 text-[#8A2BE2] z-10">
            {item.plans.map((p) => p.name).join(", ")}
          </span>
        )}
      </div>
      <div className="px-4 pt-3.5 pb-3">
        <h3 className="text-[13.5px] font-bold text-[#1A0040] leading-snug mb-1.5 line-clamp-2">
          {item.title}
        </h3>
        {item.description && (
          <p className="text-[12px] text-[#7C6A9A] leading-relaxed line-clamp-2 mb-2.5">
            {item.description}
          </p>
        )}
        <div className="flex items-center justify-between pt-2.5 border-t border-[#F5EFFF]">
          <div className="flex items-center gap-3 text-[11px] text-[#A08DBE]">
            <span className="flex items-center gap-1">
              <svg
                width="12"
                height="12"
                viewBox="0 0 12 12"
                fill="none"
                stroke="currentColor"
                strokeWidth="1.4"
              >
                <path d="M6 1.5C3.5 1.5 1.5 4 1.5 6s2 4.5 4.5 4.5S10.5 8 10.5 6 8.5 1.5 6 1.5Z" />
                <path d="M6 4v2.5L8 8" />
              </svg>
              {formatDate(item.created_at)}
            </span>
            {item.like_count > 0 && (
              <span className="flex items-center gap-1">
                <svg
                  width="12"
                  height="12"
                  viewBox="0 0 12 12"
                  fill={item.is_liked ? "#EC4899" : "none"}
                  stroke={item.is_liked ? "#EC4899" : "currentColor"}
                  strokeWidth="1.3"
                >
                  <path d="M6 10S1.5 7.5 1.5 4.5a2.5 2.5 0 0 1 4.5-1.5 2.5 2.5 0 0 1 4.5 1.5C10.5 7.5 6 10 6 10Z" />
                </svg>
                {item.like_count}
              </span>
            )}
          </div>
          <span className="text-[11px] font-semibold text-[#8A2BE2]">
            {cfg.action} →
          </span>
        </div>
      </div>
    </article>
  );
}

