function CardSkeleton() {
  return (
    <div className="bg-white rounded-2xl border border-[#EDE5F8] h-[280px] animate-pulse" />
  );
}

// ─── Sidebar: Subscribed Hubs ─────────────────────────────────────────────────
function SubscribedHubs({
  subscriptions,
  onNavigate,
}: {
  subscriptions: SubscriptionResponse[];
  onNavigate: (href: string) => void;
}) {
  const uniqueHubs = subscriptions.filter(
    (sub, index, self) =>
      index === self.findIndex((s) => s.hub.id === sub.hub.id),
  );

  if (uniqueHubs.length === 0) return null;

  return (
    <div className="bg-white rounded-2xl border border-[#EDE5F8] p-4">
      <h3 className="text-[13px] font-bold text-[#2D0052] mb-3">My Hubs</h3>
      <div className="flex flex-col gap-1.5">
        {uniqueHubs.map((sub) => {
          const color = hubColor(sub.hub.id);
          return (
            <button
              key={sub.hub.id}
              onClick={() => onNavigate(`/hubs/${sub.hub.id}`)}
              className="flex items-center gap-2.5 px-2 py-2 rounded-xl hover:bg-[#F5EFFF] transition-colors text-left w-full group"
            >
              <div
                className="w-7 h-7 rounded-full flex items-center justify-center text-white text-[11px] font-bold shrink-0"
                style={{ background: color }}
              >
                {initial(sub.hub.name)}
              </div>
              <p className="text-[12.5px] font-semibold text-[#2D0052] group-hover:text-[#8A2BE2] transition-colors truncate leading-tight">
                {sub.hub.name}
              </p>
            </button>
          );
        })}
      </div>
    </div>
  );
}

// ─── Sidebar: Suggested Creators ──────────────────────────────────────────────
function SuggestedCreators({
  onNavigate,
}: {
  onNavigate: (href: string) => void;
}) {
  const { data: creators = [], isLoading } = useExploreCreators({ limit: 4 });

  if (isLoading || creators.length === 0) return null;

  return (
    <div className="bg-white rounded-2xl border border-[#EDE5F8] p-4">
      <h3 className="text-[13px] font-bold text-[#2D0052] mb-3">
        Discover Creators
      </h3>
      <div className="flex flex-col gap-2.5">
        {creators.map((creator) => {
          const color = hubColor(
            typeof creator.id === "string" ? creator.id.charCodeAt(0) : 0,
          );
          return (
            <button
              key={creator.id}
              onClick={() =>
                creator.hub ? onNavigate(`/hubs/${creator.hub.id}`) : undefined
              }
              className="flex items-center gap-2.5 text-left w-full hover:bg-[#F5EFFF] rounded-xl px-2 py-1.5 transition-colors"
            >
              {creator.avatar_url ? (
                <img
                  src={creator.avatar_url}
                  alt={creator.username}
                  className="w-8 h-8 rounded-full object-cover shrink-0"
                />
              ) : (
                <div
                  className="w-8 h-8 rounded-full flex items-center justify-center text-white text-[12px] font-bold shrink-0"
                  style={{ background: color }}
                >
                  {initial(creator.username)}
                </div>
              )}
              <div className="flex-1 min-w-0">
                <p className="text-[12.5px] font-semibold text-[#2D0052] truncate leading-tight">
                  {creator.full_name ?? creator.username}
                </p>
                <p className="text-[11px] text-[#A08DBE] leading-tight">
                  @{creator.username}
                </p>
              </div>
            </button>
          );
        })}
      </div>
    </div>
  );
}

// ─── Page ─────────────────────────────────────────────────────────────────────
export default function FeedPage() {
  const router = useRouter();
  const [typeFilter, setTypeFilter] = useState<string>("all");

  const { data: subscriptions = [], isLoading: subsLoading } =
    useMySubscriptions();
  const activeSubscriptions = subscriptions.filter(
    (s) => s.status === "active",
  );
  const hasSubscriptions = activeSubscriptions.length > 0;

  const { data: feedContent = [], isLoading: feedLoading } = useFeedContent();
  const { data: exploreContent = [], isLoading: exploreLoading } =
    useExploreContent({ limit: 6 });

  const filteredFeed =
    typeFilter === "all"
      ? feedContent
      : feedContent.filter((item) => item.content_type === typeFilter);

  const FILTERS = [
    { key: "all", label: "All" },
    { key: "video", label: "Video" },
    { key: "image", label: "Photos" },
    { key: "text", label: "Articles" },
    { key: "pdf", label: "PDFs" },
  ];

  return (
    <div className="min-h-screen bg-[#FAFAFA]">
      <div className="max-w-[1100px] mx-auto px-6 lg:px-8 py-7">
        <div className="flex gap-7">
          {/* ── Main feed ── */}
          <div className="flex-1 min-w-0">
            <div className="mb-8">
              <h1 className="text-[20px] font-bold text-[#1A0040] mb-1">
                Your Feed
              </h1>
              <p className="text-[13px] text-[#A08DBE] mb-4">
                Latest from creators you subscribe to
              </p>

              {hasSubscriptions && (
                <div className="flex gap-2 mb-5 overflow-x-auto no-scrollbar">
                  {FILTERS.map((f) => (
                    <button
                      key={f.key}
                      onClick={() => setTypeFilter(f.key)}
                      className={cn(
                        "shrink-0 text-[12.5px] font-semibold px-4 py-1.5 rounded-full border transition-all duration-150",
                        typeFilter === f.key
                          ? "bg-[#8A2BE2] text-white border-[#8A2BE2]"
                          : "bg-white text-[#6B4F8A] border-[#EDE5F8] hover:border-[#C4A8E0] hover:text-[#8A2BE2]",
                      )}
                    >
                      {f.label}
                    </button>
                  ))}
                </div>
              )}

              {feedLoading || subsLoading ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {[...Array(4)].map((_, i) => (
                    <CardSkeleton key={i} />
                  ))}
                </div>
              ) : !hasSubscriptions ? (
                <div className="bg-white rounded-2xl border border-[#EDE5F8] p-8 text-center">
                  <div className="w-14 h-14 rounded-full bg-[#F3E8FF] flex items-center justify-center mx-auto mb-3">
                    <svg
                      width="24"
                      height="24"
                      viewBox="0 0 24 24"
                      fill="none"
                      stroke="#8A2BE2"
                      strokeWidth="1.5"
                    >
                      <circle cx="12" cy="12" r="10" />
                      <path d="M12 6v6l4 2" />
                    </svg>
                  </div>
                  <h3 className="text-[15px] font-bold text-[#1A0040] mb-1">
                    No subscriptions yet
                  </h3>
                  <p className="text-[13px] text-[#A08DBE] mb-4">
                    Subscribe to creators to see their latest content here.
                  </p>
                  <button
                    onClick={() => router.push("/explore")}
                    className="text-[13px] font-semibold px-5 py-2 rounded-full bg-[#8A2BE2] text-white hover:opacity-90 transition-opacity"
                  >
                    Explore Creators
                  </button>
                </div>
              ) : filteredFeed.length === 0 ? (
                <div className="py-12 text-center">
                  <p className="text-[13px] text-[#A08DBE]">
                    No {typeFilter === "all" ? "" : typeFilter} content from
                    your creators yet.
                  </p>
                </div>
              ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {filteredFeed.map((item) => (
                    <FeedCard
                      key={item.id}
                      item={item}
                      onClick={() =>
                        router.push(`/content/${item.id}?hub=${item.hub_id}`)
                      }
                    />
                  ))}
                </div>
              )}
            </div>

            {/* Section: Discover */}
            {exploreContent.length > 0 && (
              <div>
                <div className="flex items-center justify-between mb-4">
                  <div>
                    <h2 className="text-[17px] font-bold text-[#1A0040]">
                      Discover
                    </h2>
                    <p className="text-[12px] text-[#A08DBE]">
                      Free content from across the platform
                    </p>
                  </div>
                  <button
                    onClick={() => router.push("/explore")}
                    className="text-[12px] font-semibold text-[#8A2BE2] hover:underline underline-offset-2"
                  >
                    See all →
                  </button>
                </div>
                {exploreLoading ? (
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                    {[...Array(3)].map((_, i) => (
                      <CardSkeleton key={i} />
                    ))}
                  </div>
                ) : (
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                    {exploreContent.slice(0, 6).map((item) => (
                      <DiscoverCard
                        key={item.id}
                        item={item}
                        onClick={() => router.push(`/content/${item.id}`)}
                      />
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>

          {/* ── Sidebar ── */}
          <div className="hidden xl:flex flex-col gap-4 w-[240px] shrink-0">
            <SubscribedHubs
              subscriptions={activeSubscriptions}
              onNavigate={(href) => router.push(href)}
            />
            <SuggestedCreators onNavigate={(href) => router.push(href)} />
          </div>
        </div>
      </div>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
        .line-clamp-2 { display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
      `}</style>
    </div>
  );
}
